This pagination code silently loses items when the list length isn't an exact multiple of the page size. Find the real bug and give the minimal fix.

def get_page(items, page, size):
    start = page * size
    end = start + size
    return items[start:end]

def total_pages(items, size):
    return len(items) // size

def fetch_all(items, size):
    out = []
    for p in range(total_pages(items, size)):
        out.extend(get_page(items, p, size))
    return out

